local LxDataHelper = LxClass("LxDataHelper", nil)

function LxDataHelper.ParseAttrList(attrs)
    local attrlist = string.split(attrs,",")
    local list  = {}
    for idx,val in ipairs(attrlist) do
        local attr = LxDataHelper.ParseAttr(val)
        if attr then table.insert(list,attr) end
    end
    return list
end

function LxDataHelper.ParseAttr(attrStr)
    if string.isempty(attrStr) then
        return nil
    end
    local strList = string.split(attrStr,'=')
    if #strList >0 then 
        return  {
        refId = tonumber(strList[1]),
        type = tonumber(strList[2]),
        value =tonumber(strList[3]),
        }
    end
end

function LxDataHelper.ParseItemList(itemList)
    local rlist = {}
    if not itemList then return rlist end
    for k, v in ipairs(itemList) do
        local data = LxDataHelper.ParseItem_4(v)
        table.insert(rlist, data)
    end
    return rlist
end

function LxDataHelper.ParseItem_4(str)
    if string.isempty(str) then
        return nil
    end
    local strList = string.split(str,'=')
    if #strList < 3 then
        printErrorN("LxDataHelper.ParseItem_4, wrong cfg "..str)
    end
    local t = {
        itemType = tonumber(strList[1]),
        itemId = tonumber(strList[2]),
        itemNum =tonumber(strList[3]),
        isShowEff = strList[4] == "1",
    }
    return t
end

function LxDataHelper.ParseItem(str, sign)
    if string.isempty(str) then
        return nil
    end
    sign = sign or ','
    local strList= string.split(str,sign)
    local itemList = {}
    for k,v in ipairs(strList) do
        local t = LxDataHelper.ParseItem_4(v)
        if t then
            table.insert(itemList,t)
        end
    end
    return itemList
end


function LxDataHelper.SevenParseItems(items)
    local itemList = {}
    for k,v in pairs(items) do
        local t = {
            itemType = v.type,
            itemId = v.itemId,
            itemNum =tonumber(v.count),
            isShowEff = v.effect,
        }
        table.insert(itemList,t)
    end
    return itemList
end

