---分隔 1=1;2=2的字符串列表,分隔后的key 和value均为数字类型
function LxDataHelper.ParseIntKVList_Semicolon(str)
    local arrTmps = string.split(str, ";") or {}
    local list = {}
    for k,v in ipairs(arrTmps) do
        local intK,intV = LxDataHelper.ParseIntKV_Equal(v or "")
        if intK and intV then
            list[intK] = intV
        end
    end
    return list
end

---分隔 1=1:2:3;2=2:1:2的字符串列表,分隔后的key 和value均为数字类型
function LxDataHelper.Parse_IntK_ListIntV_Semicolon(str)
    local arrTmps = string.split(str, ";") or {}
    local list = {}
    for k,v in ipairs(arrTmps) do
        local arrKV = string.split(v or "","=") or {}
        local intK = tonumber(arrKV[1]) or 0
        local arrV = string.split(arrKV[2] or "", ":") or {}
        local tmpList = {}
        for m,n in ipairs(arrV) do
            table.insert(tmpList,tonumber(n) or 0)
        end
        list[intK] = tmpList
    end
    return list
end

function LxDataHelper.ParseItemByKeyList(str,keyList,sign)
    local separator = sign or ","
    local dataList ={}
    local tempStrs = string.split(str,separator)
    for k,v in pairs(tempStrs) do
        local tempTemp = string.split(v,"=")
        local data ={}
        for k1 ,v1 in ipairs(tempTemp) do
            local key = keyList[k1]
            if key then
                data[key] = v1
            end
        end
        table.insert(dataList,data)
    end

    return dataList
end

