function LxDataHelper.ParseRange(str)
    local s,e,cap1,cap2 = string.find(str,"{(%d+),(%d+)}")
    if not cap1 or not cap2 then
        printInfoN("LxDataHelper.ParseRange, wrong cfg "..str)
    end
    local t = {
        left = tonumber(cap1),
        right = tonumber(cap2),
    }
    return t
end

