function LxDataHelper.SevenEntryConditionRewardList(sid,entryCfgs)
    local _rewardList = {}
    for i, v in ipairs(entryCfgs) do
        local entryCfg = v
        local conditionArr = string.split(entryCfg.condition,"=")
        local condition = conditionArr[#conditionArr]
        local arr = string.split(condition,",")
        local rank1 = arr[2]
        local rank2 = arr[3] or arr[2]
        local rankStr
        if rank2 == -1 then
            rankStr = rank1 .. "+"
        else
            rankStr = rank1..","..rank2
        end
        local data = {
            rank = rankStr,
            reward = entryCfg.reward,
            sort = entryCfg.id
        }
        table.insert(_rewardList,data)
    end
    return _rewardList
end
function LxDataHelper.SevenEntryRewardList(sid,entry)
    local list = {}
    for i, v in ipairs(entry) do
        local entryCfg = gModelActivity:GetWebActivityEntryData(sid,v.pageId,v.entryId)
        table.insert(list,entryCfg)
    end
    local _rewardList = LxDataHelper.SevenEntryConditionRewardList(sid,list)
    return _rewardList
end
--获取活动排行榜奖励列表
function LxDataHelper.SevenParseRewardList(sid,page)
    local _rewardList = LxDataHelper.SevenEntryRewardList(sid,page.entry)
    return _rewardList
end
--合并同个列表的道具数量
function LxDataHelper.MergeRewardList(list)
    local kList = {}
    for i, v in ipairs(list) do
        local itemId = v.itemId
        if not kList[itemId] then
            kList[itemId] = v
        else
            local data = kList[itemId]
            data.itemNum = data.itemNum + v.itemNum
            kList[itemId] = data
        end
    end
    local list = {}
    for i, v in pairs(kList) do
        table.insert(list,v)
    end
    return list
end
--合并2个列表的道具数量
function LxDataHelper.MergeTwoRewardList(list1,list2)
    if #list2 <= 0 then return list1 end
    if #list1 <= 0 then return list2 end
    local kList = {}
    for i, v in ipairs(list2) do
        kList[v.itemId] = v
    end
    for i, v in ipairs(list1) do
        local itemId = v.itemId
        if kList[itemId]then
            local itemNum = kList[itemId].itemNum
            v.itemNum = v.itemNum + itemNum
            kList[itemId] = nil
        end
    end
    for i, v in pairs(kList) do
        table.insert(list1,v)
    end
    return list1
end

